type State = 'idle' | 'loading' | 'success' | 'error';
type Event = 'FETCH' | 'SUCCESS' | 'ERROR' | 'RESET';

const transitions: Record<State, Record<Event, State>> = {
  idle: { FETCH: 'loading', SUCCESS: 'idle', ERROR: 'idle', RESET: 'idle' },
  loading: { FETCH: 'loading', SUCCESS: 'success', ERROR: 'error', RESET: 'idle' },
  success: { FETCH: 'loading', SUCCESS: 'success', ERROR: 'error', RESET: 'idle' },
  error: { FETCH: 'loading', SUCCESS: 'success', ERROR: 'error', RESET: 'idle' },
};

class StateMachine {
  private state: State = 'idle';

  dispatch(event: Event): void {
    this.state = transitions[this.state][event];
  }

  getState(): State {
    return this.state;
  }
}

class RateLimiter {
  private requests: number[] = [];

  constructor(
    private maxRequests: number,
    private windowMs: number
  ) {}

  isAllowed(): boolean {
    const now = Date.now();
    this.requests = this.requests.filter(t => now - t < this.windowMs);

    if (this.requests.length < this.maxRequests) {
      this.requests.push(now);
      return true;
    }
    return false;
  }
}

interface Connection {
  query(sql: string): Promise<any>;
  close(): void;
}

class ConnectionPool {
  private pool: Connection[] = [];
  private inUse: Set<Connection> = new Set();

  constructor(private factory: () => Connection, private maxSize: number) {
    for (let i = 0; i < maxSize; i++) {
      this.pool.push(factory());
    }
  }

  async acquire(): Promise<Connection> {
    if (this.pool.length === 0) {
      throw new Error('Pool exhausted');
    }
    const conn = this.pool.pop()!;
    this.inUse.add(conn);
    return conn;
  }

  release(conn: Connection): void {
    this.inUse.delete(conn);
    this.pool.push(conn);
  }
}

type EventMap = {
  [key: string]: any;
};

class TypedEventEmitter<T extends EventMap> {
  private listeners: { [K in keyof T]?: ((data: T[K]) => void)[] } = {};

  on<K extends keyof T>(event: K, listener: (data: T[K]) => void): void {
    if (!this.listeners[event]) {
      this.listeners[event] = [];
    }
    this.listeners[event]!.push(listener);
  }

  emit<K extends keyof T>(event: K, data: T[K]): void {
    const eventListeners = this.listeners[event];
    if (eventListeners) {
      eventListeners.forEach(l => l(data));
    }
  }

  off<K extends keyof T>(event: K, listener: (data: T[K]) => void): void {
    const eventListeners = this.listeners[event];
    if (eventListeners) {
      const index = eventListeners.indexOf(listener);
      if (index > -1) eventListeners.splice(index, 1);
    }
  }
}

async function retry<T>(
  fn: () => Promise<T>,
  maxRetries: number = 3,
  baseDelay: number = 1000
): Promise<T> {
  let lastError: Error;

  for (let i = 0; i < maxRetries; i++) {
    try {
      return await fn();
    } catch (error) {
      lastError = error as Error;
      const delay = baseDelay * Math.pow(2, i);
      await new Promise(resolve => setTimeout(resolve, delay));
    }
  }

  throw lastError!;
}
